'use strict';

const { EVENTS, emit } = require('../bus.js');
const { CONFIG_SCHEMA, validate } = require('../config.js');
const { STRINGS } = require('../strings.js');

// Extend CONFIG_SCHEMA with notifications-specific keys.
CONFIG_SCHEMA['notifications.maxQueue'] = { type: 'number', default: 50 };

const _queues = {};
let _cfg = validate({});

function init(cfg) {
  _cfg = validate(cfg || {});
}

function send(user, message) {
  if (!_queues[user]) {
    _queues[user] = [];
  }
  const entry = { user, message, timestamp: Date.now() };
  _queues[user].push(entry);
  if (_queues[user].length > _cfg['notifications.maxQueue']) {
    _queues[user].shift();
  }
  emit(EVENTS.MESSAGE_QUEUED, entry);
  return STRINGS.MESSAGE_QUEUED
    .replace('{user}', user)
    .replace('{message}', message);
}

function list(user) {
  return (_queues[user] || []).slice();
}

function clear(user) {
  if (_queues[user]) {
    _queues[user] = [];
  }
  return STRINGS.MESSAGES_CLEARED.replace('{user}', user);
}

module.exports = { init, send, list, clear };

